import { useState, useEffect, useCallback, useMemo } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import usePageTitle from '../hooks/usePageTitle';
import s from './StrategyLifecyclePage.module.css';

const T = {
  text: tokens.color.text, textSec: tokens.color.textSecondary,
  border: tokens.color.border,
  green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue,
  amber: tokens.color.amber, purple: tokens.color.purple,
};

const STAGES = [
  { key: 'candidate', label: 'CANDIDATE', color: T.textSec, desc: 'Generated by Alpha Factory' },
  { key: 'backtest', label: 'BACKTEST', color: T.blue, desc: 'Being evaluated by backtest engine' },
  { key: 'pilot', label: 'PILOT', color: T.amber, desc: 'Paper trading validation' },
  { key: 'promoted', label: 'PROMOTED', color: T.purple, desc: 'Approved for live trading' },
  { key: 'live', label: 'LIVE', color: T.green, desc: 'Actively trading with real capital' },
  { key: 'retired', label: 'RETIRED', color: T.red, desc: 'Decommissioned due to decay or performance' },
];

function PipelineView({ stageCounts, selectedStage, onSelectStage }) {
  const maxCount = Math.max(...Object.values(stageCounts), 1);

  return (
    <GlassPanel className={s.pipelinePanel}>
      <div className={s.pipelineTitle}>Strategy Lifecycle Pipeline</div>
      <div className={s.pipelineRow}>
        {STAGES.map((stage, i) => {
          const count = stageCounts[stage.key] || 0;
          const isSelected = selectedStage === stage.key;
          const barHeight = Math.max(20, (count / maxCount) * 100);
          return (
            <div key={stage.key}
              onClick={() => onSelectStage(isSelected ? null : stage.key)}
              className={`${s.stageCol} ${isSelected ? s.stageColSelected : ''}`}
            >
              {/* Funnel bar */}
              <div className={s.barContainer}>
                <div className={s.bar} style={{
                  height: barHeight,
                  background: isSelected ? stage.color : stage.color + '66',
                  border: isSelected ? `2px solid ${stage.color}` : `1px solid ${stage.color}44`,
                }} />
              </div>
              {/* Count */}
              <div className={s.stageCount} style={{ color: stage.color }}>
                {count}
              </div>
              {/* Label */}
              <div className={s.stageLabel} style={{ color: isSelected ? stage.color : T.textSec }}>
                {stage.label}
              </div>
              {/* Arrow connector */}
              {i < STAGES.length - 1 && (
                <div className={s.arrow}>&#8594;</div>
              )}
            </div>
          );
        })}
      </div>
      {/* Funnel metrics */}
      <div className={s.funnelMetrics}>
        {[
          { label: 'Generation Rate', value: `${stageCounts.candidate || 0}/night` },
          { label: 'Promotion Rate', value: stageCounts.candidate ? `${((stageCounts.promoted || 0) / stageCounts.candidate * 100).toFixed(1)}%` : '--' },
          { label: 'Live Ratio', value: stageCounts.promoted ? `${((stageCounts.live || 0) / stageCounts.promoted * 100).toFixed(0)}%` : '--' },
          { label: 'Retirement Rate', value: stageCounts.live ? `${((stageCounts.retired || 0) / (stageCounts.live + stageCounts.retired || 1) * 100).toFixed(0)}%` : '--' },
        ].map(m => (
          <div key={m.label} className={s.metricCell}>
            <div className={s.metricValue}>{m.value}</div>
            <div className={s.metricLabel}>{m.label}</div>
          </div>
        ))}
      </div>
    </GlassPanel>
  );
}

export default function StrategyLifecyclePage() {
  usePageTitle('Strategy Lifecycle');
  const [strategies, setStrategies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedStage, setSelectedStage] = useState(null);

  const fetchData = useCallback(async () => {
    try {
      const [stratRes, candRes] = await Promise.allSettled([
        api('/strategies'),
        api('/allocator/candidates'),
      ]);

      let all = [];
      if (stratRes.status === 'fulfilled') {
        const strats = stratRes.value?.strategies || stratRes.value || [];
        all = [...all, ...strats.map(st => ({ ...st, lifecycle_stage: mapStatus(st.status) }))];
      }
      if (candRes.status === 'fulfilled') {
        const cands = candRes.value?.candidates || candRes.value?.ranked || [];
        cands.forEach(c => {
          if (!all.find(st => st.name === c.name)) {
            all.push({ ...c, lifecycle_stage: c.status || 'candidate' });
          }
        });
      }

      setStrategies(all);
      setError(null);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchData(); }, [fetchData]);

  const stageCounts = useMemo(() => {
    const counts = {};
    STAGES.forEach(st => { counts[st.key] = 0; });
    strategies.forEach(st => {
      const stage = st.lifecycle_stage || 'candidate';
      if (counts[stage] !== undefined) counts[stage]++;
      else counts.candidate++;
    });
    return counts;
  }, [strategies]);

  const stageStrategies = useMemo(() => {
    if (!selectedStage) return [];
    return strategies.filter(st => (st.lifecycle_stage || 'candidate') === selectedStage);
  }, [strategies, selectedStage]);

  const selectedMeta = STAGES.find(st => st.key === selectedStage);

  if (loading) {
    return <div className={s.loading}>Loading lifecycle data...</div>;
  }

  return (
    <div className={s.page}>
      <h1 className={s.title}>Strategy Lifecycle</h1>
      <p className={s.subtitle}>
        6-stage pipeline from generation to retirement — click a stage to see its strategies
      </p>

      {error && (
        <GlassPanel className={s.errorPanel}>
          <div className={s.errorText}>Error: {error}</div>
        </GlassPanel>
      )}

      <PipelineView stageCounts={stageCounts} selectedStage={selectedStage} onSelectStage={setSelectedStage} />

      {/* Selected stage detail */}
      {selectedStage && (
        <GlassPanel>
          <div className={s.stageHeader}>
            <span className={s.stageDot} style={{ background: selectedMeta?.color }} />
            <span className={s.stageTitle}>
              {selectedMeta?.label} Stage
            </span>
            <span className={s.stageDesc}>
              — {selectedMeta?.desc} ({stageStrategies.length} strategies)
            </span>
          </div>

          {stageStrategies.length > 0 ? (
            <div className={s.tableWrap}>
              <table className={s.detailTable}>
                <thead>
                  <tr className={s.detailTableHead}>
                    {['Strategy', 'Family', 'Sharpe', 'Win Rate', 'Max DD', 'Trades', 'Score'].map(h => (
                      <th key={h} className={s.tableHeader}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {stageStrategies.map((st, i) => (
                    <tr key={st.name || i} style={{ borderBottom: i < stageStrategies.length - 1 ? `1px solid ${T.border}` : 'none' }}>
                      <td className={s.cellName}>{st.name || '--'}</td>
                      <td className={s.cellFamily}>
                        {(st.family || '--').replace(/_/g, ' ')}
                      </td>
                      <td className={s.tableCell} style={{ color: (st.sharpe || 0) >= 1 ? T.green : T.amber }}>
                        {st.sharpe != null ? Number(st.sharpe).toFixed(2) : '--'}
                      </td>
                      <td className={s.cellText}>
                        {st.win_rate != null ? (Number(st.win_rate) * 100).toFixed(1) + '%' : '--'}
                      </td>
                      <td className={s.cellRed}>
                        {st.max_dd != null ? (Number(st.max_dd) * 100).toFixed(1) + '%' : '--'}
                      </td>
                      <td className={s.cellText}>{st.trades ?? '--'}</td>
                      <td className={s.cellPurple}>
                        {st.score != null ? Number(st.score).toFixed(1) : '--'}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <div className={s.emptyState}>
              No strategies in this stage
            </div>
          )}
        </GlassPanel>
      )}
    </div>
  );
}

function mapStatus(status) {
  if (!status) return 'candidate';
  const st = status.toLowerCase();
  if (st === 'live' || st === 'active') return 'live';
  if (st === 'promoted' || st === 'approved') return 'promoted';
  if (st === 'pilot' || st === 'paper') return 'pilot';
  if (st === 'retired' || st === 'disabled' || st === 'suppressed') return 'retired';
  if (st === 'backtested' || st === 'tested') return 'backtest';
  return 'candidate';
}
